select mb.*, m.name, m.internal_id, m.model, m.color, mc.name category from jsh_material_bom mb
left join jsh_material_extend me on mb.bar_code=me.bar_code and ifnull(me.delete_Flag,'0') !='1'
left join jsh_material m on m.id=me.material_id and ifnull(m.delete_Flag,'0') !='1'
left JOIN jsh_material_category mc on m.category_id = mc.id and ifnull(mc.delete_Flag,'0') !='1'
where 1=1


    and mb.process like #{bindProcess}



    and mb.project like #{bindProject}

and ifnull(mb.delete_flag,'0') !='1'
order by mb.id desc

    limit #{offset},#{rows}

select mb.*, m.name, m.internal_id, m.model, m.color, mc.name category from jsh_material_bom mb left join jsh_material_extend me on mb.bar_code=me.bar_code and ifnull(me.delete_Flag,'0') !='1' left join jsh_material m on m.id=me.material_id and ifnull(m.delete_Flag,'0') !='1' left JOIN jsh_material_category mc on m.category_id = mc.id and ifnull(mc.delete_Flag,'0') !='1' where 1=1
and mb.process like #{bindProcess}
and mb.project like #{bindProject}
and ifnull(mb.delete_flag,'0') !='1' order by mb.id desc

SELECT count(mb.id) from jsh_material_bom mb
where 1=1


    and mb.process like #{bindProcess}



    and mb.project like #{bindProject}

and ifnull(mb.delete_flag,'0') !='1'

